ul.li:
groups: map[string]*Group ───────────────────── ReplicationGroup struct {
Primary: *NodeInfo
Secondaries: []*NodeInfo
QuorumSize: int
Failover(deadNodeID) }

pools: map[string]*Pool ───────────────────── Pool struct {
idle: []*Conn
active: int
Get(ctx) → *Conn
Put(conn) }

map[string]*LeaderLease ───────────────────── LeaderLease struct {
NodeID: string
ExpiresAt: time.Time
Acquire() bool
Renew() bool
IsValid() bool }
